sql:
SELECT COUNT(*) AS num_alerts
FROM alert_settings
WHERE user_id = 1;

external_knowledge:
; The "top-performing stocks" refers to stocks with the highest price and volume changes on a given date; 
; The "price change" is calculated as the difference between the current closing price and the previous closing price; 
; The "volume change" is calculated as the difference between the current volume and the previous volume; 
; The "percentage change" is calculated as the absolute change divided by the previous value, multiplied by 100.

sql:
SELECT DISTINCT sp.stock_id
FROM stock_prices sp
JOIN news n ON sp.stock_id = n.stock_id AND sp.date = n.date;
